#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
inline void debug(int k){if(k>1)debug(k>>1);putchar((k&1)+'0');}
const int N=1e6+5e5+10;int n,m;
inline int Cnt(int k){int res=0;while(k){k^=(k&-k);++res;}return min(res,n-res);}
int a[N],res[N],num[N],rev[N],ans=0x3f3f3f3f;
inline void fwtxor(int *f,int len,bool flag)
{
	for(int T=1;T<=len;T=T<<1)
	{
		for(int i=0;i<=len;i+=(T<<1))
		{
			int *fl=f+i,*fr=fl+T;rep(0,T-1,j)
			{
				int tx=fl[j],ty=fr[j];
				fl[j]=(tx+ty)>>flag;fr[j]=(tx-ty)>>flag;
			}
		}
	}
}
signed main()
{
	n=read();m=read();rep(1,n,i)
	{
		int p=0;char ch=getchar();while(ch^'0'&&ch^'1')ch=getchar();
		while(ch=='0'||ch=='1')++p,a[p]=(a[p]<<1)+(ch^48),ch=getchar();
	}
	int len=(1ll<<n)-1;
	rep(0,len,i)rev[i]=(rev[i>>1]>>1)|((i&1)*((len+1)>>1));
	rep(0,len+1,i)res[i]=Cnt(i);rep(1,m,i)++num[rev[a[i]]];
	
	fwtxor(num,len,0);fwtxor(res,len,0);
//	rep(0,len,i)printf("%d ",num[i]);puts("");
//	rep(0,len,i)printf("%d ",res[i]);puts("");
	rep(0,len,i)num[i]*=res[i];fwtxor(num,len,1);
	rep(0,len,i)ans=min(ans,num[i]);printf("%lld\n",ans);
}
